package com.hospital.management.controller.prescription;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.service.impl.PrescriptionServiceImpl;import javax.servlet.*;import javax.servlet.annotation.WebServlet;import javax.servlet.http.*;import java.io.IOException;import java.util.*;@WebServlet("/prescriptions/edit")public class PrescriptionEditServlet extends HttpServlet {private final PrescriptionService service;public PrescriptionEditServlet(){this(new PrescriptionServiceImpl());}public PrescriptionEditServlet(PrescriptionService s){service=s;}protected void doGet(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{Long id=PrescriptionRequest.id(q.getParameter("id"));Prescription p=id==null?null:service.getPrescription(id,PrescriptionRequest.user(q)).orElse(null);if(p==null){r.sendError(404);return;}if(!"ACTIVE".equals(p.getStatus())){r.sendError(409);return;}show(q,r,form(p),p);}protected void doPost(HttpServletRequest q,HttpServletResponse r)throws ServletException,IOException{PrescriptionForm f=PrescriptionRequest.form(q);ServiceResult<Void>x=service.updatePrescription(f,PrescriptionRequest.audit(q),PrescriptionRequest.user(q));if(x.isSuccess()){r.sendRedirect(q.getContextPath()+"/prescriptions/view?id="+f.getPrescriptionId());return;}q.setAttribute("errors",x.getErrors());q.setAttribute("errorMessage",x.getMessage());Prescription p=f.getPrescriptionId()==null?null:service.getPrescription(f.getPrescriptionId(),PrescriptionRequest.user(q)).orElse(null);show(q,r,f,p);}private void show(HttpServletRequest q,HttpServletResponse r,PrescriptionForm f,Prescription p)throws ServletException,IOException{if(p==null){r.sendError(404);return;}q.setAttribute("prescription",p);q.setAttribute("medicalRecordId",p.getMedicalRecordId());q.setAttribute("prescriptionForm",f);q.setAttribute("formMode","EDIT");q.getRequestDispatcher("/WEB-INF/views/prescriptions/form.jsp").forward(q,r);}private PrescriptionForm form(Prescription p){PrescriptionForm f=new PrescriptionForm();f.setPrescriptionId(p.getPrescriptionId());f.setMedicalRecordId(p.getMedicalRecordId());f.setValidUntil(p.getValidUntil()==null?null:p.getValidUntil().toString());f.setNotes(p.getNotes());f.setStatus(p.getStatus());List<PrescriptionItemForm>x=new ArrayList<>();for(PrescriptionItem i:p.getItems()){PrescriptionItemForm z=new PrescriptionItemForm();z.setMedicineName(i.getMedicineName());z.setDosage(i.getDosage());z.setFrequency(i.getFrequency());z.setDuration(i.getDuration());z.setRoute(i.getRoute());z.setInstructions(i.getInstructions());x.add(z);}f.setItems(x);return f;}}
